// Beklenen alanlar:
// $json.appointment_time → "HH:mm" formatında (örn: "10:30")
// $json.timezone         → "EDT", "CDT", "PDT" vb.

const timeStr = ($json.appointment_time || '').trim();
const tz = ($json.timezone || 'PDT').trim().toUpperCase();

// ABD time zone offset'leri
const zoneOffsets = {
  PST: -8,
  PDT: -7,
  MST: -7,
  MDT: -6,
  CST: -6,
  CDT: -5,
  EST: -5,
  EDT: -4,
  AKST: -9,
  AKDT: -8,
  HST: -10,
};

if (!timeStr) {
  throw new Error('appointment_time boş veya tanımsız.');
}

const parts = timeStr.split(':');
if (parts.length < 2) {
  throw new Error('appointment_time formatı HH:mm olmalı. Gelen: ' + timeStr);
}

let hours = parseInt(parts[0], 10);
let minutes = parseInt(parts[1], 10);

if (Number.isNaN(hours) || Number.isNaN(minutes)) {
  throw new Error('Saat parse edilemedi: ' + timeStr);
}

const srcOffset = zoneOffsets[tz] ?? -7;
const pdtOffset = -7;

const MINUTES_PER_DAY = 24 * 60;
let totalMinutes = hours * 60 + minutes;

const diffMinutes = (pdtOffset - srcOffset) * 60;
totalMinutes += diffMinutes;

totalMinutes = ((totalMinutes % MINUTES_PER_DAY) + MINUTES_PER_DAY) % MINUTES_PER_DAY;

const outHours = Math.floor(totalMinutes / 60);
const outMinutes = totalMinutes % 60;

const hh = String(outHours).padStart(2, '0');
const mm = String(outMinutes).padStart(2, '0');
const pdtTime = `${hh}:${mm}`;

return {
  originalTime: timeStr,
  customerTZ: tz,
  timeInPDT: pdtTime,
};

