// Mode: Run Once for All Items

const items = $input.all();

// US timezone offset map (UTC offset, in hours)
const tzOffsetHours = {
  EDT: -4,
  EST: -5,
  CDT: -5,
  CST: -6,
  MDT: -6,
  MST: -7,
  PDT: -7,
  PST: -8,
};

const DEFAULT_TZ_ABBR = 'PDT';
const PDT_TZ_ABBR = 'PDT';

// Helper: safe number parse
const toInt = (v, def = 0) => {
  const n = parseInt(String(v).trim(), 10);
  return Number.isNaN(n) ? def : n;
};

const results = [];
const nowUtcMs = Date.now();
const ONE_DAY_MS = 24 * 60 * 60 * 1000;

for (const item of items) {
  const j = item.json;

  // 1) 24 saatlik kolon: message_sent_24
  const msgSentRaw = (j.message_sent_24 ?? '').toString().trim().toLowerCase();
  if (msgSentRaw === 'yes') {
    continue;
  }

  const body = j.body || j;

  // 2) Appointment Date
  const dateStr =
    body.appointment_date ||
    body.appointmentDate ||
    body['Appointment Date'];

  if (!dateStr) continue;

  // 3) Appointment Time + Time zone
  let timeStr =
    body.appointment_time ||
    body.appointmentTime ||
    body['Appointment Time'] ||
    body['Appointment time'] ||
    '';

  let tzAbbr =
    body.timezone ||
    body['Time zone'] ||
    '';

  timeStr = String(timeStr).trim();
  tzAbbr = String(tzAbbr).trim().toUpperCase();

  // Örnek: "00:00\ntimezon:EDT"
  if (!tzAbbr && timeStr.includes('timezon:')) {
    const parts = timeStr.split('\n');
    if (parts[0]) timeStr = parts[0].trim();
    const tzLine = parts[1] || '';
    const m = tzLine.match(/timezon:\s*([A-Za-z]+)/i);
    if (m) tzAbbr = m[1].toUpperCase();
  }

  if (!timeStr) continue;
  if (!tzAbbr) tzAbbr = DEFAULT_TZ_ABBR;

  const offsetHours = tzOffsetHours[tzAbbr] ?? tzOffsetHours[DEFAULT_TZ_ABBR];

  // 4) Tarih ve saat parçalama
  const [yearStr, monthStr, dayStr] = String(dateStr).split('-');
  const year = toInt(yearStr);
  const month = toInt(monthStr);
  const day = toInt(dayStr);

  const [hStr, mStr] = String(timeStr).split(':');
  const hour = toInt(hStr);
  const minute = toInt(mStr);

  if (!year || !month || !day) continue;

  // 5) Müşteri TZ → UTC
  const apptUtcMs = Date.UTC(year, month - 1, day, hour - offsetHours, minute);

  // 6) 24 saatlik pencere
  const diffMs = apptUtcMs - nowUtcMs;
  if (diffMs <= 0 || diffMs > ONE_DAY_MS) continue;

  // 7) PDT'ye göre tarih-saat
  const apptDateObj = new Date(apptUtcMs);

  const pdtFormatter = new Intl.DateTimeFormat('en-US', {
    timeZone: 'America/Los_Angeles',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false,
  });

  const pdtParts = Object.fromEntries(
    pdtFormatter.formatToParts(apptDateObj).map(p => [p.type, p.value])
  );

  const pdtFormatted = `${pdtParts.year}-${pdtParts.month}-${pdtParts.day} ${pdtParts.hour}:${pdtParts.minute} ${PDT_TZ_ABBR}`;

  // 8) Müşteri local string
  const customerLocal = `${dateStr} ${timeStr} ${tzAbbr}`;

  // 9) Output
  const outJson = {
    ...j,
    customerAppointmentLocal: customerLocal,
    appointmentTimePDT: pdtFormatted,
  };

  results.push({ json: outJson });
}

return results;

